/**
 * @summary List all outcomes in the savings ledger
 */
export const getListOutcomesUrl = (params?: ListOutcomesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/outcomes?${stringifiedParams}`
    : `/api/outcomes`;
};

export const listOutcomes = async (
  params?: ListOutcomesParams,
  options?: RequestInit,
): Promise<OutcomeLedgerEntry[]> => {
  return customFetch<OutcomeLedgerEntry[]>(getListOutcomesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListOutcomesQueryKey = (params?: ListOutcomesParams) => {
  return [`/api/outcomes`, ...(params ? [params] : [])] as const;
};

export const getListOutcomesQueryOptions = <
  TData = Awaited<ReturnType<typeof listOutcomes>>,
  TError = ErrorType<unknown>,
>(
  params?: ListOutcomesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listOutcomes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListOutcomesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listOutcomes>>> = ({
    signal,
  }) => listOutcomes(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listOutcomes>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListOutcomesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listOutcomes>>
>;
export type ListOutcomesQueryError = ErrorType<unknown>;

/**
 * @summary List all outcomes in the savings ledger
 */

export function useListOutcomes<
  TData = Awaited<ReturnType<typeof listOutcomes>>,
  TError = ErrorType<unknown>,
>(
  params?: ListOutcomesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listOutcomes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListOutcomesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

